// Compile GitHub activity into a structured summary for Claude
const commits = $input.all()[0].json;
const issues = $input.all()[1].json;
const prs = $input.all()[2].json;

const repo = $('Schedule Trigger').item.json.repo;
const weekStart = $moment().subtract(7, 'days').format('YYYY-MM-DD');
const weekEnd = $moment().format('YYYY-MM-DD');

// Count stats
const commitAuthors = {};
(Array.isArray(commits) ? commits : []).forEach(c => {
  const author = c.commit?.author?.name || c.author?.login || 'unknown';
  commitAuthors[author] = (commitAuthors[author] || 0) + 1;
});

const newIssues = (Array.isArray(issues) ? issues : []).filter(i => !i.pull_request);
const closedIssues = newIssues.filter(i => i.state === 'closed');
const mergedPRs = (Array.isArray(prs) ? prs : []).filter(p => p.merged_at);

// Format raw data for Claude
const activityData = {
  repo,
  period: `${weekStart} to ${weekEnd}`,
  stats: {
    totalCommits: (Array.isArray(commits) ? commits : []).length,
    topContributors: Object.entries(commitAuthors).sort((a,b) => b[1] - a[1]).slice(0, 5).map(([name, count]) => ({ name, commits: count })),
    issuesOpened: newIssues.filter(i => i.state === 'open').length,
    issuesClosed: closedIssues.length,
    prsMerged: mergedPRs.length,
    prsOpen: (Array.isArray(prs) ? prs : []).filter(p => !p.merged_at && p.state === 'open').length,
  },
  highlights: {
    recentCommits: (Array.isArray(commits) ? commits : []).slice(0, 10).map(c => ({
      message: c.commit?.message?.split('\n')[0] || '',
      author: c.commit?.author?.name || 'unknown',
      date: c.commit?.author?.date
    })),
    newIssues: newIssues.filter(i => i.state === 'open').slice(0, 5).map(i => ({
      title: i.title,
      url: i.html_url,
      labels: (i.labels || []).map(l => l.name)
    })),
    mergedPRs: mergedPRs.slice(0, 5).map(p => ({
      title: p.title,
      url: p.html_url,
      author: p.user?.login
    }))
  }
};

return {
  prompt: `You are a developer relations writer. Write a friendly, narrative weekly summary of this GitHub repo's activity.

Repository: ${activityData.repo}
Period: ${activityData.period}

Stats:
- ${activityData.stats.totalCommits} commits by ${activityData.stats.topContributors.length} contributors
- ${activityData.stats.issuesOpened} new issues, ${activityData.stats.issuesClosed} closed
- ${activityData.stats.prsMerged} PRs merged, ${activityData.stats.prsOpen} open

Top contributors: ${activityData.stats.topContributors.map(c => `${c.name} (${c.commits})`).join(', ')}

Recent commits: ${activityData.highlights.recentCommits.map(c => `- ${c.message} (${c.author})`).join('\n')}

New issues: ${activityData.highlights.newIssues.map(i => `- ${i.title}`).join('\n')}

Merged PRs: ${activityData.highlights.mergedPRs.map(p => `- ${p.title} by ${p.author}`).join('\n')}

Format the response as:
## 📊 Weekly Dev Summary — ${activityData.repo}
**${weekStart} → ${weekEnd}**

### 🎯 Highlights
[3-5 sentences narrative of the most interesting activity]

### 📈 Stats
| Metric | Count |
|--------|-------|
| Commits | ${activityData.stats.totalCommits} |
| Issues Opened | ${activityData.stats.issuesOpened} |
| Issues Closed | ${activityData.stats.issuesClosed} |
| PRs Merged | ${activityData.stats.prsMerged} |

### 👥 Top Contributors
[List with emoji and commits]

### 🔥 What Shipped
[PR descriptions]

### 🐛 What Needs Attention
[Open issues that look important]

### 💭 Community Pulse
[1-2 sentences on overall project health]

Be concise, professional, and slightly playful. Use emoji sparingly.`
};

const response = $input.first().json;
const summary = response.content?.[0]?.text || 'Error: no response from Claude';
return { summary, generatedAt: new Date().toISOString() };
